//! MioCodec stage-by-stage comparison test.
//!
//! Compares Rust MioCodec implementation output against Python reference .npy files
//! generated by `vendor/miocodec_test/gen_reference.py`.
//!
//! Usage:
//!   cargo run --bin miocodec_test [--features cuda]

use candle_core::{DType, Device, Tensor};
use candle_nn::{Module, VarBuilder};
use std::path::Path;

use candle_miotts::models::config::MioCodecConfig;
use candle_miotts::models::miocodec::{linear_interpolate, MioCodecDecoder};
use candle_miotts::models::wavlm::{GlobalEncoder, WavLM};

// ──────── .npy reader (NumPy format v1.0) ────────

fn load_npy(path: &Path) -> (Vec<usize>, Vec<f32>) {
    let data = std::fs::read(path).unwrap_or_else(|e| panic!("Failed to read {}: {e}", path.display()));
    assert_eq!(&data[..6], b"\x93NUMPY", "Not a .npy file: {}", path.display());

    let _major = data[6];
    let _minor = data[7];
    let header_len = u16::from_le_bytes([data[8], data[9]]) as usize;
    let header = std::str::from_utf8(&data[10..10 + header_len]).unwrap();

    // Parse dtype
    let descr = extract_field(header, "descr");
    let is_f32 = descr.contains("f4") || descr.contains("float32");
    let is_i64 = descr.contains("i8") || descr.contains("int64");
    let is_f64 = descr.contains("f8") || descr.contains("float64");

    // Parse shape
    let shape_str = extract_field(header, "shape");
    let shape: Vec<usize> = shape_str
        .trim_matches(|c: char| c == '(' || c == ')' || c.is_whitespace())
        .split(',')
        .filter(|s| !s.trim().is_empty())
        .map(|s| s.trim().parse().unwrap())
        .collect();

    let numel: usize = shape.iter().product();
    let payload = &data[10 + header_len..];

    let values: Vec<f32> = if is_f32 {
        assert_eq!(payload.len(), numel * 4, "Payload size mismatch for f32");
        (0..numel)
            .map(|i| f32::from_le_bytes([
                payload[i * 4], payload[i * 4 + 1], payload[i * 4 + 2], payload[i * 4 + 3],
            ]))
            .collect()
    } else if is_f64 {
        assert_eq!(payload.len(), numel * 8, "Payload size mismatch for f64");
        (0..numel)
            .map(|i| f64::from_le_bytes([
                payload[i * 8], payload[i * 8 + 1], payload[i * 8 + 2], payload[i * 8 + 3],
                payload[i * 8 + 4], payload[i * 8 + 5], payload[i * 8 + 6], payload[i * 8 + 7],
            ]) as f32)
            .collect()
    } else if is_i64 {
        assert_eq!(payload.len(), numel * 8, "Payload size mismatch for i64");
        (0..numel)
            .map(|i| i64::from_le_bytes([
                payload[i * 8], payload[i * 8 + 1], payload[i * 8 + 2], payload[i * 8 + 3],
                payload[i * 8 + 4], payload[i * 8 + 5], payload[i * 8 + 6], payload[i * 8 + 7],
            ]) as f32)
            .collect()
    } else {
        panic!("Unsupported dtype {descr} in {}", path.display());
    };

    (shape, values)
}

fn extract_field<'a>(header: &'a str, field: &str) -> &'a str {
    let key = format!("'{field}':");
    let start = header.find(&key).unwrap_or_else(|| panic!("field '{field}' not found in npy header"));
    let rest = &header[start + key.len()..];
    let rest = rest.trim_start();
    // Find the value: either quoted string or tuple
    if rest.starts_with('\'') {
        let end = rest[1..].find('\'').unwrap() + 1;
        &rest[1..end]
    } else if rest.starts_with('(') {
        let end = rest.find(')').unwrap() + 1;
        &rest[..end]
    } else {
        let end = rest.find(',').unwrap_or(rest.len());
        rest[..end].trim()
    }
}

fn load_npy_tensor(path: &Path, device: &Device) -> Tensor {
    let (shape, values) = load_npy(path);
    Tensor::from_vec(values, shape.as_slice(), device).unwrap()
}

// ──────── Comparison helpers ────────

struct CompareResult {
    max_abs_err: f32,
    rms_err: f32,
    cosine_sim: f32,
    py_rms: f32,
    rs_rms: f32,
}

fn compare_tensors(rust: &Tensor, python: &Tensor) -> CompareResult {
    let r = rust.to_dtype(DType::F32).unwrap().flatten_all().unwrap().to_vec1::<f32>().unwrap();
    let p = python.to_dtype(DType::F32).unwrap().flatten_all().unwrap().to_vec1::<f32>().unwrap();
    assert_eq!(r.len(), p.len(), "Length mismatch: rust={} vs python={}", r.len(), p.len());

    let mut max_abs = 0.0f32;
    let mut sum_sq_err = 0.0f64;
    let mut sum_sq_py = 0.0f64;
    let mut sum_sq_rs = 0.0f64;
    let mut dot = 0.0f64;

    for (rv, pv) in r.iter().zip(p.iter()) {
        let err = (rv - pv).abs();
        max_abs = max_abs.max(err);
        sum_sq_err += (err as f64) * (err as f64);
        sum_sq_py += (*pv as f64) * (*pv as f64);
        sum_sq_rs += (*rv as f64) * (*rv as f64);
        dot += (*rv as f64) * (*pv as f64);
    }

    let n = r.len() as f64;
    let rms_err = (sum_sq_err / n).sqrt() as f32;
    let py_rms = (sum_sq_py / n).sqrt() as f32;
    let rs_rms = (sum_sq_rs / n).sqrt() as f32;
    let cosine_sim = if sum_sq_rs > 0.0 && sum_sq_py > 0.0 {
        (dot / (sum_sq_rs.sqrt() * sum_sq_py.sqrt())) as f32
    } else {
        0.0
    };

    CompareResult {
        max_abs_err: max_abs,
        rms_err,
        cosine_sim,
        py_rms,
        rs_rms,
    }
}

fn report(stage: &str, result: &CompareResult, rms_tol: f32, cos_tol: f32) -> bool {
    let pass = result.rms_err <= rms_tol && result.cosine_sim >= cos_tol;
    let status = if pass { "PASS" } else { "FAIL" };
    println!(
        "[{status}] {stage:30} | rms_err={:.6} (tol={:.6}) | cos_sim={:.6} (tol={:.6}) | max_abs={:.6} | py_rms={:.4} rs_rms={:.4}",
        result.rms_err, rms_tol,
        result.cosine_sim, cos_tol,
        result.max_abs_err,
        result.py_rms, result.rs_rms,
    );
    pass
}

// ──────── Main test ────────

fn main() {
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| "warn".into()),
        )
        .init();

    let ref_dir = Path::new("vendor/miocodec_test/reference_data");
    assert!(ref_dir.exists(), "Reference data not found at {}", ref_dir.display());

    // Load model
    let device = Device::Cpu;
    let miocodec_path = find_miocodec_safetensors();
    println!("Loading model from: {}", miocodec_path.display());
    let vb = unsafe {
        VarBuilder::from_mmaped_safetensors(&[&miocodec_path], DType::F32, &device).unwrap()
    };

    let cfg = MioCodecConfig::default();
    let decoder = MioCodecDecoder::load(vb, &cfg).unwrap();

    // Load reference inputs
    let codec_indices = load_npy_tensor(&ref_dir.join("input_codec_indices.npy"), &device);
    let speaker_emb = load_npy_tensor(&ref_dir.join("input_speaker_emb.npy"), &device);

    println!("\n=== MioCodec Stage-by-Stage Comparison ===\n");
    let mut all_pass = true;

    // ── Stage 1: FSQ Decode ──
    let fsq_out = decoder.fsq.forward(&codec_indices).unwrap();
    let py_fsq = load_npy_tensor(&ref_dir.join("fsq_decode_output.npy"), &device);
    let r = compare_tensors(&fsq_out, &py_fsq);
    all_pass &= report("Stage 1: FSQ Decode", &r, 1e-5, 0.9999);

    // ── Stage 2: wave_prenet ──
    let prenet_in = fsq_out.unsqueeze(0).unwrap(); // (1, 24, 768)
    let prenet_out = decoder.wave_prenet.forward(&prenet_in, None).unwrap();
    let py_prenet = load_npy_tensor(&ref_dir.join("wave_prenet_output.npy"), &device);
    let r = compare_tensors(&prenet_out, &py_prenet);
    all_pass &= report("Stage 2: wave_prenet", &r, 0.01, 0.999);

    // ── Stage 3: wave_conv_upsample ──
    let conv_in = prenet_out.transpose(1, 2).unwrap(); // (1, 512, 24)
    let conv_out = decoder.wave_conv_upsample.forward(&conv_in).unwrap(); // (1, 512, 48)
    let py_conv = load_npy_tensor(&ref_dir.join("wave_conv_upsample_output.npy"), &device);
    let r = compare_tensors(&conv_out, &py_conv);
    all_pass &= report("Stage 3: conv_upsample", &r, 0.01, 0.999);

    // ── Stage 4: Interpolate ──
    let seq_len = codec_indices.dim(0).unwrap();
    let stft_length = seq_len * cfg.wave_upsample_factor;
    let interp_out = linear_interpolate(&conv_out, stft_length).unwrap();
    let py_interp = load_npy_tensor(&ref_dir.join("interpolate_output.npy"), &device);
    let r = compare_tensors(&interp_out, &py_interp);
    all_pass &= report("Stage 4: interpolate", &r, 0.01, 0.999);

    // ── Stage 5: wave_prior_net ──
    let prior_out = decoder.wave_prior_net.forward(&interp_out).unwrap();
    let py_prior = load_npy_tensor(&ref_dir.join("wave_prior_net_output.npy"), &device);
    let r = compare_tensors(&prior_out, &py_prior);
    all_pass &= report("Stage 5: wave_prior_net", &r, 0.01, 0.999);

    // ── Stage 6: wave_decoder (8-layer Transformer with AdaLN-Zero) ──
    // Slightly looser tolerance: 8 transformer layers accumulate numerical noise
    let dec_in = prior_out.transpose(1, 2).unwrap(); // (1, 48, 512)
    let spk_cond = speaker_emb.unsqueeze(0).unwrap(); // (1, 128)
    let dec_out = decoder.wave_decoder.forward(&dec_in, Some(&spk_cond)).unwrap();
    let py_dec = load_npy_tensor(&ref_dir.join("wave_decoder_output.npy"), &device);
    let r = compare_tensors(&dec_out, &py_dec);
    all_pass &= report("Stage 6: wave_decoder", &r, 0.1, 0.998);

    // ── Stage 7: wave_post_net (cascaded from stage 6) ──
    let post_in = dec_out.transpose(1, 2).unwrap(); // (1, 512, 48)
    let post_out = decoder.wave_post_net.forward(&post_in).unwrap();
    let py_post = load_npy_tensor(&ref_dir.join("wave_post_net_output.npy"), &device);
    let r = compare_tensors(&post_out, &py_post);
    all_pass &= report("Stage 7: wave_post_net", &r, 0.1, 0.997);

    // ── Stage 8: wave_upsampler ──
    // Rust returns (B, C, T'), Python returns (B, T', C) — transpose Rust for comparison
    let up_out = decoder.upsampler.forward(&post_out).unwrap();
    let py_up = load_npy_tensor(&ref_dir.join("wave_upsampler_output.npy"), &device);
    let up_out_compare = up_out.transpose(1, 2).unwrap(); // (B, C, T') → (B, T', C)
    let r = compare_tensors(&up_out_compare, &py_up);
    all_pass &= report("Stage 8: wave_upsampler", &r, 0.15, 0.99);

    // ── Stage 9: istft_head (cascaded) ──
    // iSTFTHead expects (B, C, T) input, which is our up_out (not transposed)
    let istft_out = decoder.istft_head.forward(&up_out).unwrap();
    let py_istft = load_npy_tensor(&ref_dir.join("istft_audio_output.npy"), &device);
    let r = compare_tensors(&istft_out, &py_istft);
    all_pass &= report("Stage 9: istft_head (cascaded)", &r, 0.05, 0.95);

    // ── Stage 9b: istft_head (isolated — Python upsampler output → Rust iSTFT) ──
    // This isolates iSTFT correctness from accumulated errors in earlier stages
    let py_up_for_istft = py_up.transpose(1, 2).unwrap(); // (B, T', C) → (B, C, T')
    let istft_isolated = decoder.istft_head.forward(&py_up_for_istft).unwrap();
    let r = compare_tensors(&istft_isolated, &py_istft);
    all_pass &= report("Stage 9b: istft_head (isolated)", &r, 0.001, 0.9999);

    // ── Isolation tests: feed Python ref into each Rust stage individually ──
    println!("\n=== Isolated Stage Tests (Python input → Rust stage) ===\n");

    // Stage 6 isolated: Python prior_net output → Rust wave_decoder
    let py_prior_for_dec = py_prior.transpose(1, 2).unwrap(); // (B, C, T) → (B, T, C)
    let dec_isolated = decoder.wave_decoder.forward(&py_prior_for_dec, Some(&spk_cond)).unwrap();
    let r = compare_tensors(&dec_isolated, &py_dec);
    report("Stage 6 isolated: wave_decoder", &r, 0.1, 0.998);

    // Stage 7 isolated: Python decoder output → Rust post_net
    let py_dec_for_post = py_dec.transpose(1, 2).unwrap(); // (B, T, C) → (B, C, T)
    let post_isolated = decoder.wave_post_net.forward(&py_dec_for_post).unwrap();
    let r = compare_tensors(&post_isolated, &py_post);
    report("Stage 7 isolated: wave_post_net", &r, 0.01, 0.999);

    // Stage 8 isolated: Python post_net output → Rust upsampler
    let up_isolated = decoder.upsampler.forward(&py_post).unwrap();
    let up_isolated_cmp = up_isolated.transpose(1, 2).unwrap();
    let r = compare_tensors(&up_isolated_cmp, &py_up);
    report("Stage 8 isolated: wave_upsampler", &r, 0.01, 0.999);

    // Full isolated: Python post_net → Rust upsampler → Rust iSTFT
    let istft_from_pypost = decoder.istft_head.forward(&up_isolated).unwrap();
    let r = compare_tensors(&istft_from_pypost, &py_istft);
    report("Stage 8+9 isolated: up+istft", &r, 0.01, 0.999);

    println!("\n{}", if all_pass { "=== ALL STAGES PASSED ===" } else { "=== SOME STAGES FAILED ===" });

    // ── Speaker Embedding Comparison (if reference data exists) ──
    let spk_waveform_path = ref_dir.join("spk_waveform_16k.npy");
    if spk_waveform_path.exists() {
        println!("\n=== Speaker Embedding Pipeline Comparison ===\n");

        // Load Python's 16kHz waveform
        let py_wav16k = load_npy_tensor(&spk_waveform_path, &device);
        println!("Python 16kHz waveform: {:?}", py_wav16k.shape());

        // Load WavLM
        let wavlm_path = find_wavlm_pth();
        println!("Loading WavLM from: {}", wavlm_path.display());
        let wavlm_vb = candle_nn::VarBuilder::from_pth(&wavlm_path, DType::F32, &device).unwrap();
        let wavlm = WavLM::load(wavlm_vb, &[1, 2]).unwrap();

        // Run WavLM on Python's 16kHz audio
        let rs_ssl = wavlm.extract_global_features(&py_wav16k).unwrap();
        println!("Rust SSL features: {:?}", rs_ssl.shape());

        // Compare with Python's SSL features
        let py_ssl = load_npy_tensor(&ref_dir.join("spk_ssl_features_avg.npy"), &device);
        let r = compare_tensors(&rs_ssl, &py_ssl);
        report("WavLM SSL features (avg)", &r, 0.1, 0.99);

        // Per-layer comparison
        for layer in [1, 2] {
            let py_layer = load_npy_tensor(&ref_dir.join(format!("spk_wavlm_layer{layer}.npy")), &device);
            // We need per-layer output, but our WavLM only gives averaged.
            // Just report the Python stats for reference.
            println!("  Python layer {layer}: rms={:.4}", {
                let vals = py_layer.flatten_all().unwrap().to_vec1::<f32>().unwrap();
                (vals.iter().map(|v| v * v).sum::<f32>() / vals.len() as f32).sqrt()
            });
        }

        // Load GlobalEncoder and test
        let ge_vb = unsafe {
            candle_nn::VarBuilder::from_mmaped_safetensors(&[&miocodec_path], DType::F32, &device).unwrap()
        };
        let global_encoder = GlobalEncoder::load(ge_vb.pp("global_encoder")).unwrap();

        let rs_emb = global_encoder.forward(&rs_ssl).unwrap();
        let py_emb = load_npy_tensor(&ref_dir.join("input_speaker_emb.npy"), &device);
        println!("Rust speaker emb: {:?}, Python speaker emb: {:?}", rs_emb.shape(), py_emb.shape());

        let r = compare_tensors(&rs_emb, &py_emb);
        report("Speaker Embedding (full)", &r, 0.1, 0.99);

        // Print first 5 values for comparison
        let rs_vals: Vec<f32> = rs_emb.to_vec1().unwrap();
        let py_vals: Vec<f32> = py_emb.to_vec1().unwrap();
        println!("  Rust first5:   {:?}", &rs_vals[..5]);
        println!("  Python first5: {:?}", &py_vals[..5]);
    }

    if !all_pass {
        std::process::exit(1);
    }
}

fn find_wavlm_pth() -> std::path::PathBuf {
    let cache_dir = dirs_next::home_dir()
        .unwrap()
        .join(".cache/huggingface/hub/models--microsoft--wavlm-base-plus/snapshots");
    if cache_dir.exists() {
        for entry in std::fs::read_dir(&cache_dir).unwrap() {
            let entry = entry.unwrap();
            let pth = entry.path().join("pytorch_model.bin");
            if pth.exists() {
                return pth;
            }
        }
    }
    panic!("WavLM pytorch_model.bin not found in HuggingFace cache");
}

fn find_miocodec_safetensors() -> std::path::PathBuf {
    // Look in HuggingFace cache
    let cache_dir = dirs_next::home_dir()
        .unwrap()
        .join(".cache/huggingface/hub/models--Aratako--MioCodec-25Hz-44.1kHz-v2/snapshots");

    if cache_dir.exists() {
        for entry in std::fs::read_dir(&cache_dir).unwrap() {
            let entry = entry.unwrap();
            let st = entry.path().join("model.safetensors");
            if st.exists() {
                return st;
            }
        }
    }
    panic!("MioCodec model.safetensors not found in HuggingFace cache");
}
